#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int longestValidParentheses(char * s){
   int max = 0;
   int *stack = (int *)malloc(strlen(s) * sizeof(int));
   int top = -1;
   stack[++top] = -1;
   for (int i = 0; i < strlen(s); i++) {
      if (s[i] == '(') {
         stack[++top] = i;
      } else {
         top--;
         if (top == -1) {
            stack[++top] = i;
         } else {
            max = (max > i - stack[top]) ? max : i - stack[top];
         }
      }
   }
   free(stack);
   return max;
}

int main() {
   char s[] = "((())())()()(()())";
   printf("%d\n", longestValidParentheses(s));
   return 0;
}

code.C++:
#include <iostream>
#include <stack>
#include <string>

int longestValidParentheses(std::string s) {
   int max = 0;
   std::stack<int> stack;
   stack.push(-1);
   for (int i = 0; i < s.length(); i++) {
      if (s[i] == '(') {
         stack.push(i);
      } else {
         stack.pop();
         if (stack.empty()) {
            stack.push(i);
         } else {
            max = std::max(max, i - stack.top());
         }
      }
   }
   return max;
}

int main() {
   std::string s = "((())())()()(()())";
   std::cout << longestValidParentheses(s) << std::endl;
   return 0;
}

